/**
 * dagre-lite - Minimal DAG layout engine for Gas Town GUI
 *
 * Implements layered graph drawing (Sugiyama-style):
 * 1. Assign nodes to ranks/layers via longest-path
 * 2. Order nodes within layers to reduce crossings
 * 3. Assign x/y coordinates with configurable spacing
 *
 * API compatible with dagre's core layout interface.
 */

// eslint-disable-next-line no-unused-vars
const dagre = (() => {
  class Graph {
    constructor(opts = {}) {
      this._directed = opts.directed !== false;
      this._nodes = new Map();
      this._edges = [];
      this._graphLabel = {};
    }

    setGraph(label) {
      this._graphLabel = { ...this._graphLabel, ...label };
      return this;
    }

    graph() {
      return this._graphLabel;
    }

    setNode(id, label = {}) {
      this._nodes.set(id, { ...label, id });
      return this;
    }

    node(id) {
      return this._nodes.get(id) || null;
    }

    nodes() {
      return [...this._nodes.keys()];
    }

    setEdge(v, w, label = {}) {
      this._edges.push({ v, w, ...label });
      return this;
    }

    edges() {
      return this._edges.map(e => ({ v: e.v, w: e.w }));
    }

    edge(v, w) {
      return this._edges.find(e => e.v === v && e.w === w) || null;
    }

    successors(id) {
      return this._edges.filter(e => e.v === id).map(e => e.w);
    }

    predecessors(id) {
      return this._edges.filter(e => e.w === id).map(e => e.v);
    }

    nodeCount() {
      return this._nodes.size;
    }

    edgeCount() {
      return this._edges.length;
    }
  }

  function layout(g) {
    const graphOpts = g.graph();
    const rankdir = graphOpts.rankdir || 'TB';
    const nodesep = graphOpts.nodesep || 50;
    const ranksep = graphOpts.ranksep || 80;
    const marginx = graphOpts.marginx || 20;
    const marginy = graphOpts.marginy || 20;

    const nodeIds = g.nodes();
    if (nodeIds.length === 0) return;

    // Step 1: Assign ranks via longest path from roots
    const ranks = new Map();
    const visited = new Set();

    function assignRank(id) {
      if (visited.has(id)) return ranks.get(id) || 0;
      visited.add(id);

      const preds = g.predecessors(id);
      if (preds.length === 0) {
        ranks.set(id, 0);
        return 0;
      }

      let maxPredRank = 0;
      for (const pred of preds) {
        const predRank = assignRank(pred);
        if (predRank + 1 > maxPredRank) maxPredRank = predRank + 1;
      }
      ranks.set(id, maxPredRank);
      return maxPredRank;
    }

    for (const id of nodeIds) {
      assignRank(id);
    }

    // Step 2: Group nodes by rank
    const layers = new Map();
    for (const id of nodeIds) {
      const rank = ranks.get(id) || 0;
      if (!layers.has(rank)) layers.set(rank, []);
      layers.get(rank).push(id);
    }

    const sortedRanks = [...layers.keys()].sort((a, b) => a - b);

    // Step 3: Order nodes within each layer (barycenter heuristic)
    for (let pass = 0; pass < 4; pass++) {
      for (const rank of sortedRanks) {
        const layer = layers.get(rank);
        if (rank === 0) continue;

        const prevLayer = layers.get(sortedRanks[sortedRanks.indexOf(rank) - 1]);
        if (!prevLayer) continue;

        const prevPos = new Map();
        prevLayer.forEach((id, idx) => prevPos.set(id, idx));

        layer.sort((a, b) => {
          const predsA = g.predecessors(a);
          const predsB = g.predecessors(b);
          const avgA = predsA.length > 0
            ? predsA.reduce((s, p) => s + (prevPos.get(p) || 0), 0) / predsA.length
            : 0;
          const avgB = predsB.length > 0
            ? predsB.reduce((s, p) => s + (prevPos.get(p) || 0), 0) / predsB.length
            : 0;
          return avgA - avgB;
        });
      }
    }

    // Step 4: Assign coordinates
    const isHorizontal = rankdir === 'LR' || rankdir === 'RL';
    let maxWidth = 0;
    let maxHeight = 0;

    for (const rank of sortedRanks) {
      const layer = layers.get(rank);
      layer.forEach((id, idx) => {
        const node = g.node(id);
        const w = node.width || 100;
        const h = node.height || 40;

        if (isHorizontal) {
          node.x = marginx + rank * (w + ranksep) + w / 2;
          node.y = marginy + idx * (h + nodesep) + h / 2;
        } else {
          node.x = marginx + idx * (w + nodesep) + w / 2;
          node.y = marginy + rank * (h + ranksep) + h / 2;
        }

        const right = node.x + w / 2;
        const bottom = node.y + h / 2;
        if (right > maxWidth) maxWidth = right;
        if (bottom > maxHeight) maxHeight = bottom;
      });
    }

    // Set graph dimensions
    const gl = g.graph();
    gl.width = maxWidth + marginx;
    gl.height = maxHeight + marginy;

    // Compute edge points
    for (const edge of g.edges()) {
      const src = g.node(edge.v);
      const tgt = g.node(edge.w);
      if (src && tgt) {
        const e = g.edge(edge.v, edge.w);
        if (e) {
          e.points = [
            { x: src.x, y: src.y + (src.height || 40) / 2 },
            { x: (src.x + tgt.x) / 2, y: (src.y + tgt.y) / 2 },
            { x: tgt.x, y: tgt.y - (tgt.height || 40) / 2 },
          ];
        }
      }
    }
  }

  return {
    graphlib: { Graph },
    layout,
  };
})();

if (typeof module !== 'undefined' && module.exports) {
  module.exports = dagre;
}
